#include <bits/stdc++.h>
using namespace std;
int n,x,a[15],num=0,sum=0;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>x>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	if(a[1]!=1)
	{
		cout<<-1;
		return 0;
	}
	while(sum<x)
	{
		for(int i=n;i>=1;i--)
		{
			if(a[i]<=sum+1)
			{
				sum+=a[i];
				num++;
				break;
			}
		}
	}
	cout<<num;
	return 0;
}
